    80→    process.stdin.on('data', (chunk) => { data += chunk.toString(); });
    81→    process.stdin.on('end', () => { clearTimeout(timer); resolve(data); });
    82→    process.stdin.on('error', (err) => { clearTimeout(timer); reject(err); });
