 * - COORDINATES WITH: LoadContext (both run at SessionStart)
 * - MUST RUN BEFORE: None (visual feedback only)
 * - MUST RUN AFTER: None
 *
 * ERROR HANDLING:
 * - Missing settings: Error logged, exits with error code
 * - Banner tool failure: Error logged, exits with error code
 *
 * PERFORMANCE:
 * - Non-blocking: Yes (banner is informational)
 * - Typical execution: <100ms
 * - Skipped for subagents: Yes
 *
 * BANNER MODES:
 * - nano (<40 cols): Minimal single-line
 * - micro (40-59 cols): Compact with stats
 * - mini (60-84 cols): Medium layout
 * - normal (85+ cols): Full neofetch-style
 */

import { readFileSync } from 'fs';
import { join } from 'path';
import { spawnSync, execSync } from 'child_process';

import { getPaiDir, getSettingsPath } from './lib/paths';

const paiDir = getPaiDir();
const settingsPath = getSettingsPath();

(async () => {
  try {
    const settings = JSON.parse(readFileSync(settingsPath, 'utf-8'));

    // Check if this is a subagent session - if so, exit silently
    const claudeProjectDir = process.env.CLAUDE_PROJECT_DIR || '';
    const isSubagent = claudeProjectDir.includes('/.claude/Agents/') ||
                      process.env.CLAUDE_AGENT_TYPE !== undefined;

    if (isSubagent) {
      process.exit(0);
    }

    // Run the banner tool
    const bannerPath = join(paiDir, 'skills/PAI/Tools/Banner.ts');
    const result = spawnSync('bun', ['run', bannerPath], {
      encoding: 'utf-8',
      stdio: ['inherit', 'pipe', 'pipe'],
      env: {
        ...process.env,
        // Pass through terminal detection env vars
        COLUMNS: process.env.COLUMNS,
        KITTY_WINDOW_ID: process.env.KITTY_WINDOW_ID,
      }
    });

    if (result.stdout) {
      console.log(result.stdout);
    }

    // Send voice notification for startup greeting (fire-and-forget, non-blocking)
    const voiceId = settings.daidentity?.voiceId || 's3TPKV1kjDlVtZbl4Ksh';
    const voiceSettings = settings.daidentity?.voice;

    // Use AbortController with short timeout to prevent hanging
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), 1000); // 1s max

    fetch('http://localhost:8888/notify', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      signal: controller.signal,
      body: JSON.stringify({
        message: `${settings.daidentity?.name || 'PAI'} here, ready to go.`,
        title: 'Session Start',
        voice_enabled: true,
        voice_id: voiceId,
        voice_settings: voiceSettings ? {
          stability: voiceSettings.stability ?? 0.5,
          similarity_boost: voiceSettings.similarity_boost ?? 0.75,
          style: voiceSettings.style ?? 0.0,
          speed: voiceSettings.speed ?? 1.0,
          use_speaker_boost: voiceSettings.use_speaker_boost ?? true,
        } : undefined,
      }),
    })
      .catch(() => {}) // Silent fail if voice server not running
      .finally(() => clearTimeout(timeoutId));

    // Set initial tab title - always start fresh
    // New sessions are a clean slate, no context from previous sessions
    const isKitty = process.env.TERM === 'xterm-kitty' || process.env.KITTY_LISTEN_ON;
    if (isKitty) {
      try {
        execSync(`kitty @ set-tab-title "Ready to work..."`, { stdio: 'ignore', timeout: 2000 });
      } catch {
        // Silent failure - tab title is non-critical
      }
    }

    process.exit(0);
  } catch (error) {
    console.error('StartupGreeting: Failed to display banner', error);
    process.exit(1);
  }
})();

