    46→
    47→/**
    48→ * Send voice notification for integrity check start.
    49→ * Fire-and-forget - doesn't block.
    50→ * Uses ElevenLabs TTS via voice server.
    51→ * Includes 4-second delay to let main voice handler finish speaking first.
    52→ */
    53→async function notifyIntegrityStart(): Promise<void> {
    54→  try {
    55→    // Wait 4 seconds for main voice handler to finish speaking
    56→    await new Promise(resolve => setTimeout(resolve, 4000));
    57→
    58→    // Load identity for voice settings
    59→    const { getIdentity } = await import('../lib/identity');
    60→    const identity = getIdentity();
    61→
    62→    const voiceId = identity.voiceId || 's3TPKV1kjDlVtZbl4Ksh';
    63→    const voiceSettings = identity.voice;
    64→
    65→    await fetch('http://localhost:8888/notify', {
    66→      method: 'POST',
    67→      headers: { 'Content-Type': 'application/json' },
    68→      body: JSON.stringify({
    69→        message: 'Checking system integrity for recent changes.',
    70→        title: `${identity.name} says`,
    71→        voice_enabled: true,
    72→        voice_id: voiceId,
    73→        voice_settings: voiceSettings ? {
    74→          stability: voiceSettings.stability ?? 0.5,
    75→          similarity_boost: voiceSettings.similarity_boost ?? 0.75,
    76→          style: voiceSettings.style ?? 0.0,
    77→          speed: voiceSettings.speed ?? 1.0,
    78→          use_speaker_boost: voiceSettings.use_speaker_boost ?? true,
    79→        } : undefined,
    80→      }),
    81→    });
    82→  } catch {
    83→    // Voice server might not be running - silent fail
    84→  }
    85→}
    86→
    87→/**
    88→ * Update the integrity state file.
    89→ */
    90→function updateIntegrityState(changes: FileChange[]): void {
    91→  try {
    92→    if (!existsSync(STATE_DIR)) {
    93→      mkdirSync(STATE_DIR, { recursive: true });
    94→    }
    95→
    96→    const state = {
    97→      last_run: new Date().toISOString(),
    98→      last_changes_hash: hashChanges(changes),
    99→      cooldown_until: getCooldownEndTime(),
   100→    };
   101→
   102→    writeFileSync(STATE_FILE, JSON.stringify(state, null, 2));
   103→    console.error('[SystemIntegrity] Updated state file');
   104→  } catch (error) {
   105→    console.error('[SystemIntegrity] Failed to update state:', error);
   106→  }
   107→}
   108→
   109→/**
   110→ * Spawn the IntegrityMaintenance script in the background.
   111→ */
   112→function spawnIntegrityMaintenance(
   113→  changes: FileChange[],
   114→  hookInput: HookInput
   115→): void {
   116→  try {
   117→    // Check if script exists
   118→    if (!existsSync(INTEGRITY_SCRIPT)) {
   119→      console.error('[SystemIntegrity] IntegrityMaintenance.ts not found:', INTEGRITY_SCRIPT);
   120→      return;
   121→    }
   122→
   123→    // Pre-compute title and metadata for logging
   124→    const filteredChanges = changes.filter(c => c.category !== null);
