     1→/**
     2→ * Observability Integration
     3→ * Sends hook events to the Agent Visibility Dashboard at localhost:4000
     4→ *
     5→ * Dashboard: https://github.com/disler/claude-code-hooks-multi-agent-observability
     6→ * Server runs at: localhost:4000
     7→ * Client dashboard: localhost:5173
     8→ */
     9→
    10→export interface ObservabilityEvent {
    11→  source_app: string;
    12→  session_id: string;
    13→  hook_event_type: 'PreToolUse' | 'PostToolUse' | 'UserPromptSubmit' | 'Notification' | 'Stop' | 'SubagentStop' | 'SessionStart' | 'SessionEnd' | 'PreCompact';
    14→  timestamp: string;
    15→  transcript_path?: string;
    16→  summary?: string;
    17→  tool_name?: string;
    18→  tool_input?: any;
    19→  tool_output?: any;
    20→  agent_type?: string;
    21→  model?: string;
    22→  [key: string]: any;
    23→}
    24→
    25→/**
    26→ * Send event to observability dashboard
    27→ * Fails silently if dashboard is not running - doesn't block hook execution
    28→ */
    29→export async function sendEventToObservability(event: ObservabilityEvent): Promise<void> {
    30→  try {
    31→    const response = await fetch('http://localhost:4000/events', {
    32→      method: 'POST',
    33→      headers: {
    34→        'Content-Type': 'application/json',
    35→        'User-Agent': 'PAI-Hook/1.0'
    36→      },
    37→      body: JSON.stringify(event),
    38→    });
    39→
    40→    if (!response.ok) {
    41→      // Log error but don't throw - dashboard may be offline
    42→      console.error(`Observability server returned status: ${response.status}`);
    43→    }
    44→  } catch (error) {
    45→    // Fail silently - dashboard may not be running
    46→    // This is intentional - hooks should never fail due to observability issues
    47→    // Uncomment below for debugging:
    48→    // console.error('Failed to send event to observability:', error);
    49→  }
    50→}
    51→
    52→/**
    53→ * Helper to get current timestamp in ISO format
    54→ */
    55→export function getCurrentTimestamp(): string {
    56→  return new Date().toISOString();
    57→}
    58→
    59→/**
    60→ * Helper to get source app name from environment or default to 'PAI'
    61→ */
    62→export function getSourceApp(): string {
    63→  return process.env.PAI_SOURCE_APP || 'PAI';
    64→}
    65→

